function setActiveSideMenu(){let t=localStorage.getItem(WLVSTools_ActiveSideMenuParent),n=$("#"+t);n.addClass("active");n.parent("li").addClass("menu-open");let i=localStorage.getItem(WLVSTools_ActiveSideMenu);$("#"+i).addClass("active")}function sendApiRequest(n,t,i=null,r="application/x-www-form-urlencoded"){return $.ajax({url:n,method:t,data:i,contentType:r})}var WLVSTools_ActiveSideMenuParent="WLVSTools_ActiveSideMenuParent",WLVSTools_ActiveSideMenu="WLVSTools_ActiveSideMenu";$(function(){$("a.nav-link").on("click",function(){if($(this).parents().is(".sidebar")){$(".sidebar").children("a").removeClass("active");let n=$(this).parents("ul[data-parent-menu-id]").data("parent-menu-id"),t=$(this).attr("id");localStorage.setItem(WLVSTools_ActiveSideMenuParent,n);localStorage.setItem("WLVSTools_ActiveSideMenu",t);setActiveSideMenu()}});setActiveSideMenu()});